def _record_usage(span, usage: Any) -> None:
    """Set OpenInference token-count attributes from a usage dict/object (#203)."""
    if not usage:
        return

    def g(key: str):
        return usage.get(key) if isinstance(usage, dict) else getattr(usage, key, None)

    prompt_toks = g("input_tokens")
    completion_toks = g("output_tokens")
    # Anthropic/Agent-SDK report cache tokens in SEPARATE fields excluded from
    # input_tokens; on a cached-prefix run they can dominate real input. Fold them
    # into the prompt/total counts (and emit the OpenInference cache slots) so
    # llm.token_count.total reflects all tokens processed, not an undercount on the
    # very tier where usage visibility matters most (#280). Real spend is still
    # tracked separately via llm.cost_usd.

